function union(aFmt, bFmt : FixFormat_t) return FixFormat_t is
begin
    return (
        S => maximum(aFmt.S, bFmt.S),
        I => maximum(aFmt.I, bFmt.I),
        F => maximum(aFmt.F, bFmt.F)
    );
end function;

-----------------------------------------------------------------------------------------------
